powershell -Command "
\$projects = @(
    'C:\Users\Administrator\Desktop\GL3\품번선택1',
    'C:\Users\Administrator\Desktop\GL3\5차',
    'C:\Users\Administrator\Desktop\GL3\5차(B)',
    'C:\Users\Administrator\Desktop\GL3\NOISE TEST'
)

foreach (\$projectDir in \$projects) {
    \$designerFiles = Get-ChildItem -Path \$projectDir -Filter '*Designer.vb' -Recurse
    foreach (\$file in \$designerFiles) {
        \$lines = @(Get-Content \$file.FullName)
        \$newLines = @()
        foreach (\$line in \$lines) {
            if (\$line -notmatch '\.OcxState\s*=\s*CType') {
                \$newLines += \$line
            }
        }
        Set-Content \$file.FullName \$newLines -Encoding UTF8
        Write-Host \"Cleaned: \$(\$file.FullName)\"
    }
}
"

